    22→// Very simple security middleware - no external dependencies
    23→function setupBasicSecurity(app: express.Application) {
    24→  // Basic security headers
    25→  app.use((req, res, next) => {
    26→    res.setHeader('X-Content-Type-Options', 'nosniff');
    27→    res.setHeader('X-Frame-Options', 'DENY');
    28→    res.setHeader('X-XSS-Protection', '1; mode=block');
