    36→function setupCors(app: express.Application) {
    37→  app.use((req, res, next) => {
    38→    const origin = req.header("origin");
    39→
    40→    // Allow localhost origins for Expo web development (any port)
    41→    const isLocalhost =
    42→      origin?.startsWith("http://localhost:") ||
    43→      origin?.startsWith("http://127.0.0.1:");
    44→
    45→    // Allow mobile app origins (Expo Go)
    46→    const isExpoOrigin = 
    47→      origin?.includes("expo") ||
    48→      origin?.includes("exp.direct") ||
    49→      origin?.includes("exp://") ||
    50→      origin?.startsWith("http://192.168.") ||
    51→      origin?.startsWith("http://10.") ||
    52→      origin?.startsWith("http://172.") ||
    53→      !origin; // Allow requests with no origin
    54→
    55→    // Allow Replit dev domain
    56→    const isReplitOrigin =
    57→      origin?.includes(".replit.dev") ||
    58→      origin?.includes(".repl.co") ||
    59→      origin?.includes(".replit.app");
    60→
    61→    // Set CORS headers
    62→    if (isLocalhost || isExpoOrigin || isReplitOrigin || !origin) {
    63→      res.header("Access-Control-Allow-Origin", origin || "http://localhost:8081");
    64→      res.header(
    65→        "Access-Control-Allow-Methods",
    66→        "GET, POST, PUT, DELETE, OPTIONS, PATCH",
    67→      );
    68→      res.header(
    69→        "Access-Control-Allow-Headers", 
    70→        "Content-Type, Authorization, X-Requested-With, Accept, Origin, User-Agent, DNT, Cache-Control, X-Mx-ReqToken, Keep-Alive, X-Requested-With, If-Modified-Since"
    71→      );
    72→      res.header("Access-Control-Allow-Credentials", "true");
    73→      res.header("Access-Control-Max-Age", "86400"); // 24 hours
    74→    }
    75→
    76→    if (req.method === "OPTIONS") {
    77→      return res.sendStatus(200);
    78→    }
    79→
    80→    next();
    81→  });
    82→}
