    99→// Basic input validation
   100→function validateInput(req: Request, res: Response, next: NextFunction) {
   101→  // XSS Protection
   102→  const sanitizeString = (str: string): string => {
   103→    return str
   104→      .replace(/<script[^>]*>.*?<\/script>/gi, '')
   105→      .replace(/<javascript[^>]*>.*?<\/javascript>/gi, '')
   106→      .replace(/on\w+\s*=\s*["'][^"']*["']/gi, '');
   107→  };
   108→
   109→  // SQL Injection Protection
   110→  const detectSqlInjection = (str: string): boolean => {
   111→    const sqlPatterns = [
   112→      /(exec(\s|\+)+(s|x)p\w+)/i,
   113→      /(union(.*?)select)/i,
   114→      /(select(.*?)from)/i,
   115→      /(insert(.*?)into)/i,
   116→      /(delete(.*?)from)/i,
   117→      /(update(.*?)set)/i,
   118→      /(drop(.*?)table)/i,
   119→      /(create(.*?)table)/i,
   120→      /(alter(.*?)table)/i,
   121→      /(exec(.*?)\()/i
   122→    ];
   123→    
   124→    return sqlPatterns.some((pattern: RegExp) => pattern.test(str));
   125→  };
   126→
   127→  // Sanitize request body
   128→  if (req.body && typeof req.body === 'object') {
   129→    const checkAndSanitize = (obj: any): boolean => {
   130→      if (typeof obj === 'object' && obj !== null) {
   131→        for (const key in obj) {
   132→          const val = obj[key];
   133→          if (typeof val === 'string') {
   134→            if (detectSqlInjection(val)) return true;
   135→            obj[key] = sanitizeString(val);
   136→          } else if (typeof val === 'object') {
   137→            if (checkAndSanitize(val)) return true;
   138→          }
   139→        }
   140→      }
   141→      return false;
   142→    };
   143→
   144→    if (checkAndSanitize(req.body)) {
   145→      return res.status(400).json({ error: 'Invalid input detected' });
   146→    }
   147→  }
   148→
   149→  // Sanitize query parameters
   150→  if (req.query) {
   151→    for (const key in req.query) {
   152→      if (typeof req.query[key] === 'string') {
   153→        req.query[key] = sanitizeString(req.query[key] as string);
   154→      }
   155→    }
   156→  }
   157→
   158→  next();
   159→}
