   161→// Basic authentication middleware
   162→function authenticateToken(req: Request, res: Response, next: NextFunction) {
   163→  const authHeader = req.headers['authorization'];
   164→  const token = authHeader && authHeader.split(' ')[1];
   165→
   166→  if (!token) {
   167→    return res.status(401).json({ error: 'Access token required' });
   168→  }
   169→
   170→  // Simple JWT verification (without external library for now)
   171→  try {
   172→    const decoded = JSON.parse(atob(token.split('.')[1]));
   173→    if (decoded.exp && decoded.exp < Date.now() / 1000) {
   174→      return res.status(403).json({ error: 'Token expired' });
   175→    }
   176→    req.user = decoded;
   177→    next();
   178→  } catch (error) {
   179→    return res.status(403).json({ error: 'Invalid token' });
   180→  }
   181→}
