   183→function setupRequestLogging(app: express.Application) {
   184→  app.use((req, res, next) => {
   185→    const start = Date.now();
   186→    const path = req.path;
   187→    let capturedJsonResponse: Record<string, unknown> | undefined = undefined;
   188→
   189→    const originalResJson = res.json;
   190→    res.json = function (bodyJson, ...args) {
   191→      capturedJsonResponse = bodyJson;
   192→      return originalResJson.apply(res, [bodyJson, ...args]);
   193→    };
