   198→      const duration = Date.now() - start;
   199→
   200→      let logLine = `${req.method} ${path} ${res.statusCode} in ${duration}ms`;
   201→      if (capturedJsonResponse) {
   202→        logLine += ` :: ${JSON.stringify(capturedJsonResponse)}`;
   203→      }
   204→
   205→      if (logLine.length > 80) {
   206→        logLine = logLine.slice(0, 79) + "…";
   207→      }
   208→
   209→      log(logLine);
   210→    });
   211→
   212→    next();
   213→  });
