   251→    .replace(/EXPS_URL_PLACEHOLDER/g, expsUrl)
   252→    .replace(/APP_NAME_PLACEHOLDER/g, appName);
   253→
   254→  res.setHeader("Content-Type", "text/html; charset=utf-8");
