   258→function proxyToMetro(req: Request, res: Response) {
   259→  const http = require("http");
   260→
   261→  // Strip content-length since body may have been modified by body-parser
   262→  // Strip origin so Metro's CORS check doesn't reject the proxied browser request
   263→  const headers = { ...req.headers, host: "localhost:8080" };
   264→  delete headers["content-length"];
   265→  delete headers["origin"];
   266→
   267→  const options = {
   268→    hostname: "localhost",
   269→    port: 8080,
   270→    path: req.url,
   271→    method: req.method,
   272→    headers,
   273→  };
   274→
   275→  const proxyReq = http.request(options, (proxyRes: any) => {
   276→    // Forward all headers from Metro back to the client
   277→    Object.keys(proxyRes.headers).forEach((key) => {
   278→      try { res.setHeader(key, proxyRes.headers[key]); } catch (_) {}
   279→    });
   280→    res.status(proxyRes.statusCode);
   281→    proxyRes.pipe(res, { end: true });
   282→  });
   283→
   284→  proxyReq.on("error", (err: Error) => {
   285→    log("Metro proxy error:", err.message);
   286→    if (!res.headersSent) {
   287→      res.status(502).json({ error: "Expo dev server not reachable. Make sure the Start Frontend workflow is running." });
   288→    }
   289→  });
   290→
   291→  // Body may already be parsed by express.json() — write it manually then end
   292→  if (req.body && Object.keys(req.body).length > 0) {
   293→    const bodyStr = JSON.stringify(req.body);
   294→    proxyReq.setHeader("content-length", Buffer.byteLength(bodyStr));
   295→    proxyReq.write(bodyStr);
   296→  }
   297→  proxyReq.end();
   298→}
