   350→function setupErrorHandler(app: express.Application) {
   351→  // 404 handler
   352→  app.use((req: Request, res: Response) => {
   353→    res.status(404).json({ error: 'Route not found' });
   354→  });
   355→
   356→  // Global error handler
   357→  app.use((err: unknown, _req: Request, res: Response, next: NextFunction) => {
   358→    const error = err as {
   359→      status?: number;
   360→      statusCode?: number;
   361→      message?: string;
   362→      code?: string;
   363→    };
   364→
   365→    const status = error.status || error.statusCode || 500;
   366→    const message = process.env.NODE_ENV === 'production' 
   367→      ? 'Internal Server Error' 
   368→      : (error.message || 'Internal Server Error');
   369→
   370→    console.error('Error:', {
   371→      status,
   372→      message: error.message,
   373→      timestamp: new Date().toISOString()
   374→    });
   375→
   376→    if (res.headersSent) {
   377→      return next(err);
   378→    }
   379→
   380→    return res.status(status).json({ 
   381→      error: message,
   382→      timestamp: new Date().toISOString()
   383→    });
   384→  });
   385→}
