  { id: 'tagliklar', name: 'Tagliklar', query: 'rice grains cereal staple food product transparent background', file: 'sub-taglik' },
];

const results = [];

for (const cat of categories) {
  try {
    const res = await imageSearch({ query: cat.query, count: 5 });
    const items = (res.results ?? []).filter(r => r.properties?.url);

    let downloaded = false;
    for (const item of items) {
      try {
        const imgUrl = item.properties?.url;
        if (!imgUrl) continue;
        const resp = await fetch(imgUrl, { signal: AbortSignal.timeout(8000) });
        if (!resp.ok) continue;
        const buf = Buffer.from(await resp.arrayBuffer());
        if (buf.length < 5000) continue; // skip tiny images
        const ext = imgUrl.includes('.png') ? '.png' : '.jpg';
        const filePath = `assets/subcategory-images/${cat.file}${ext}`;
        await fs.writeFile(filePath, buf);
        results.push({ ...cat, filePath, success: true });
        downloaded = true;
        break;
      } catch {}
    }
    if (!downloaded) results.push({ ...cat, success: false });
  } catch(e) {
    results.push({ ...cat, success: false, error: e.message });
  }
}

